import sqlite3
import os
import time
import re
import random
import unicodedata
import uuid
import hmac
import hashlib
from flask import Flask, request, render_template, redirect, url_for, session, jsonify, g
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(Config.DATABASE_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def aegis_v8_shield(data):
    if not data:
        return ""

    # Layer 0: Unicode Normalization (Prevents obfuscation via homoglyphs)
    data = unicodedata.normalize('NFKC', data)

    # Layer 1: Whitespace and Comment annihilation
    data = re.sub(r'\s+', '', data)
    data = re.sub(r'/\*.*?\*/', '', data)
    data = data.replace("--", "").replace("#", "")

    # Layer 2: Recursive Filtering for logic/joining keywords
    # Strips until empty to prevent 'ANDANDND' style bypasses
    recursive_keywords = ["UNION", "WHERE", "AND", "LIKE", "CASE", "WHEN", "THEN", "SUBSTR", "RANDOMBLOB", "CAST", "COALESCE", "BY"]
    changed = True
    while changed:
        original = data
        # Sort keywords by length to prevent partial matches destroying structure
        for kw in sorted(recursive_keywords, key=len, reverse=True):
            regex = re.compile(re.escape(kw), re.IGNORECASE)
            data = regex.sub("", data)
        if data == original:
            changed = False

    # Layer 3: Non-Recursive Filtering for fundamental structure
    # Forces use of 'SELSELECTECT' style bypasses for these specific terms
    structure_keywords = ["SELECT", "FROM", "LIMIT", "GROUP", "ORDER", "HAVING", "IN", "EXISTS", "OR"]
    for kw in sorted(structure_keywords, key=len, reverse=True):
        regex = re.compile(re.escape(kw), re.IGNORECASE)
        data = regex.sub("", data)

    return data

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user'] = user['username']
            session['role'] = user['role']
            session['handshake_secret'] = str(uuid.uuid4())
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/api/v2/handshake', methods=['GET'])
def handshake():
    if 'user' not in session:
        return jsonify({"error": "Unauthorized"}), 401
    return jsonify({"handshake_token": session.get('handshake_secret')})

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    db = get_db()
    manifests = db.execute('SELECT * FROM satellite_inventory LIMIT 10').fetchall()
    return render_template('dashboard.html', manifests=manifests)

@app.route('/api/v2/docs')
def api_docs():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('api_docs.html')

@app.route('/api/v2/telemetry/archive', methods=['POST'])
def telemetry_archive():
    token = request.headers.get('X-Archived-Token')
    signature = request.headers.get('X-Integrity-Signature')
    handshake_token = request.headers.get('X-Handshake-Token')

    # Multi-factor Authorization Check
    if not token or not signature or handshake_token != session.get('handshake_secret'):
        return jsonify({"status": "error", "message": "Missing or invalid authorization context"}), 401

    # Integrity Verification (HMAC-SHA256)
    # Required to prevent basic repeater-style attacks without automation script
    sig_content = f"{handshake_token}{token}"
    expected_sig = hmac.new(session.get('handshake_secret').encode(), sig_content.encode(), hashlib.sha256).hexdigest()
    if signature != expected_sig:
        return jsonify({"status": "error", "message": "Integrity signature mismatch"}), 403

    # Rate Limiting: 1.5s cooldown remains enforced
    last_req = session.get('last_api_call', 0)
    if time.time() - last_req < 1.5:
        return jsonify({"status": "error", "message": "Rate limit exceeded. System cooling down."}), 429
    session['last_api_call'] = time.time()

    # Tightened character limit (145 -> 110)
    if len(token) > 110:
        return jsonify({"status": "error", "message": "Header segment exceeds safety limit (110 chars)"}), 400

    # Apply Aegis-v8 Shield
    filtered_token = aegis_v8_shield(token)

    db = get_db()
    try:
        # Blind injection point
        query = f"SELECT id FROM telemetry_archives WHERE archive_token = '{filtered_token}'"
        db.execute(query).fetchone()
    except Exception:
        pass

    # Total Blindness with High Variable Jitter (0.05s to 0.5s variance)
    time.sleep(0.05 + random.uniform(0.0, 0.45))
    return jsonify({"status": "accepted", "registry_id": "VKA-ST-7700"}), 202

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

